const e=JSON.parse('{"key":"v-5a2ac3c9","path":"/project/%E5%AE%9A%E5%88%B6%E5%8C%96%E5%AF%BC%E5%87%BAexecl%E7%9A%84%E5%B0%81%E8%A3%85%EF%BC%8C%E6%AF%94%E5%A6%82%E8%A1%A8%E5%A4%B4%E5%90%88%E5%B9%B6%E3%80%81%E5%A4%9A%E4%B8%AAsheet%E7%AD%89%E6%A0%BC%E5%BC%8F.html","title":"定制化导出execl的封装，比如表头合并、多个sheet等格式","lang":"zh-CN","frontmatter":{"title":"定制化导出execl的封装，比如表头合并、多个sheet等格式","isTimeLine":true,"date":"2026-03-01T00:00:00.000Z","category":["前端"],"tag":["JavaScript","node"]},"headers":[{"level":3,"title":"场景","slug":"场景","link":"#场景","children":[]},{"level":3,"title":"解决方案","slug":"解决方案","link":"#解决方案","children":[]},{"level":3,"title":"实现","slug":"实现","link":"#实现","children":[]},{"level":3,"title":"难点场景实现","slug":"难点场景实现","link":"#难点场景实现","children":[]}],"git":{"createdTime":1773458982000,"updatedTime":1773458982000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":3.03,"words":909},"filePathRelative":"project/定制化导出execl的封装，比如表头合并、多个sheet等格式.md","localizedDate":"2026年3月1日","excerpt":"<h3> 场景</h3>\\n<ol>\\n<li>系统很多地方都有用到表格导出，并且导出的格式多样化：比如多级表头；</li>\\n<li>导出数据有多个sheet、样式特别复杂比如表头是纵向配置的等等。<br>\\n</li>\\n</ol>\\n<h3> 解决方案</h3>\\n<p>主要使用<code>exceljs</code>插件实现复杂样式、单元格格式控制</p>\\n<h3> 实现</h3>\\n<h4> 思路</h4>\\n<ol>\\n<li>根据输入的参数<code>columns</code>、<code>tableData</code>构建为标题数组、合并单元格数组；</li>\\n<li>创建表格与工作表: <code>const workbook = new ExcelJS.Workbook();const worksheet = workbook.addWorksheet(\\"Sheet1\\");</code></li>\\n<li>生成标题，单行表头或多级表头；</li>\\n<li>添加数据：将tableData使用<code>sheet.addRows(tableData)</code>添加进表格；</li>\\n<li>设置每一列样式：\\n<ul>\\n<li><code>sheet.getRow</code>获取具体行</li>\\n<li><code>row.eachCell((cell)=&gt;{})</code>，设置每一格单元格的<code>cell.border、cell.font</code>等样式</li>\\n</ul>\\n</li>\\n<li>表格转流: <code>const buffer = await workbook.xlsx.writeBuffer()</code>；</li>\\n<li>下载表格：创建<code>Blob</code>对象，创建下载a链接，触发点击事件；</li>\\n</ol>"}');export{e as data};
